#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int can_catch(int kid_performance, int scooter_performance, int guard_performance) {
    return (long long)guard_performance * scooter_performance > (long long)kid_performance;
}

int count_valid_assignments(int *guards, int *scooters, int n, int kid_performance, int kid_scooter) {
    int count = 0;
    int *assignment = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        assignment[i] = i;
    }
    do {
        int valid = 1;
        for (int i = 0; i < n; i++) {
            if (!can_catch(kid_performance * kid_scooter, scooters[assignment[i]], guards[i])) {
                valid = 0;
                break;
            }
        }
        if (valid) {
            count = (count + 1) % MOD;
        }
    } while (next_permutation(assignment, assignment + n));
    free(assignment);
    return count;
}

int next_permutation(int *arr, int *end) {
    int *i = end;
    i--;
    if (i == arr) {
        return 0;
    }
    int *j = i;
    i--;
    while (i != arr && *i >= *j) {
        i--;
    }
    if (i == arr) {
        return 0;
    }
    int *k = end;
    while (*k <= *i) {
        k--;
    }
    int temp = *i;
    *i = *k;
    *k = temp;
    int *l = j;
    k = end;
    while (l < k) {
        temp = *l;
        *l = *k;
        *k = temp;
        l++;
        k--;
    }
    return 1;
}

int main() {
    int t;
    scanf("%d", &t);
    for (int i = 0; i < t; i++) {
        int kid_performance, kid_scooter;
        scanf("%d %d", &kid_performance, &kid_scooter);
        int n;
        scanf("%d", &n);
        int *guards = (int*)malloc(n * sizeof(int));
        int *scooters = (int*)malloc(n * sizeof(int));
        for (int j = 0; j < n; j++) {
            scanf("%d", &guards[j]);
        }
        for (int j = 0; j < n; j++) {
            scanf("%d", &scooters[j]);
        }
        qsort(guards, n, sizeof(int), compare);
        qsort(scooters, n, sizeof(int), compare);
        int count = count_valid_assignments(guards, scooters, n, kid_performance, kid_scooter);
        printf("Case %d: %d\n", i + 1, count);
        free(guards);
        free(scooters);
    }
    return 0;
}

