import java.util.Arrays;
import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static boolean can_catch(int kid_performance, int scooter_performance, int guard_performance) {
        return (long)guard_performance * scooter_performance > (long)kid_performance;
    }
    public static int count_valid_assignments(int[] guards, int[] scooters, int n, int kid_performance, int kid_scooter) {
        int count = 0;
        do {
            int valid = 1;
            for (int i = 0; i < n; i++) {
                if (!can_catch(kid_performance * kid_scooter, scooters[i], guards[i])) {
                    valid = 0;
                    break;
                }
            }
            if (valid) {
                count = (count + 1) % MOD;
            }
        } while (next_permutation(scooters));
        return count;
    }
    public static boolean next_permutation(int[] arr) {
        int i = arr.length - 2;
        while (i >= 0 && arr[i] >= arr[i + 1]) {
            i--;
        }
        if (i < 0) {
            return false;
        }
        int j = arr.length - 1;
        while (j > i && arr[j] <= arr[i]) {
            j--;
        }
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
        int l = i + 1;
        j = arr.length - 1;
        while (l < j) {
            temp = arr[l];
            arr[l] = arr[j];
            arr[j] = temp;
            l++;
            j--;
        }
        return true;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        for (int i = 0; i < t; i++) {
            int kid_performance = scanner.nextInt();
            int kid_scooter = scanner.nextInt();
            int n = scanner.nextInt();
            int[] guards = new int[n];
            int[] scooters = new int[n];
            for (int j = 0; j < n; j++) {
                guards[j] = scanner.nextInt();
            }
            for (int j = 0; j < n; j++) {
                scooters[j] = scanner.nextInt();
            }
            Arrays.sort(guards);
            Arrays.sort(scooters);
            int count = count_valid_assignments(guards, scooters, n, kid_performance, kid_scooter);
            System.out.println("Case " + (i + 1) + ": " + count);
        }
    }
}

