let idx = 0;
const MOD = 1000000007;
function can_catch(kid_performance, scooter_performance, guard_performance) {
    return (guard_performance * scooter_performance) > (kid_performance);
}
function count_valid_assignments(guards, scooters, n, kid_performance, kid_scooter) {
    let count = 0;
    const perms = getPermutations(scooters);
    for (let p of perms) {
        let valid = 1;
        for (let i = 0; i < n; i++) {
            if (!can_catch(kid_performance * kid_scooter, p[i], guards[i])) {
                valid = 0;
                break;
            }
        }
        if (valid) {
            count = (count + 1) % MOD;
        }
    }
    return count;
}
function getPermutations(arr) {
    if (arr.length === 1) {
        return [arr];
    }
    const result = [];
    for (let i = 0; i < arr.length; i++) {
        const rest = arr.slice(0, i).concat(arr.slice(i + 1));
        for (let p of getPermutations(rest)) {
            result.push([arr[i]].concat(p));
        }
    }
    return result;
}
